/**
 * GINGEBALL — PLAYER ASSET MANIFEST
 * lib/player-assets.ts
 *
 * Canonical player ID map + bobblehead asset manifest + likeness briefs.
 * All types match the Gingeball bobblehead system specification.
 *
 * NBA CDN headshots: https://cdn.nba.com/headshots/nba/latest/1040x760/{nbaPlayerId}.png
 * Bobblehead posters/models: TBD — set bobbleheadStatus: "approved" when assets arrive.
 * onError fallback in portrait components gracefully handles missing/wrong IDs.
 *
 * Render priority (PlayerBobblehead):
 * 1. bobbleheadModelUrl (approved 3D model)
 * 2. bobbleheadPosterUrl (approved poster illustration)
 * 3. profileHeroPortraitUrl
 * 4. dossierPortraitUrl
 * 5. portraitStaticUrl / portraitUrl
 * 6. GingeballFallback token
 */

// ─────────────────────────────────────────────────────────────────────────────
// TYPE SYSTEM
// ─────────────────────────────────────────────────────────────────────────────

/** Canonical player ID entry — slug-keyed source of truth for NBA ID resolution */
export interface PlayerIdMapEntry {
  slug: string;
  name: string;
  team: string;
  nbaPlayerId?: number;
  sourcePlayerId?: string;
  status: "verified" | "needs-review" | "missing";
  notes?: string;
}

/** Reference image pipeline for bobblehead creation */
export interface BobbleheadReferenceEntry {
  slug: string;
  name: string;
  team: string;
  nbaPlayerId?: number;
  referenceImages: {
    primary?: string;
    front?: string;
    threeQuarter?: string;
    profile?: string;
    action?: string;
  };
  source: {
    provider?: "project-owned" | "licensed-api" | "nba-reference" | "manual" | "missing";
    sourceId?: string;
    sourceUrl?: string;
    retrievedAt?: string;
  };
  referenceStatus: "verified" | "needs-review" | "missing";
}

/** Art direction brief for bobblehead likeness creation */
export interface PlayerLikenessBrief {
  slug: string;
  name: string;
  referenceImageUrls: string[];
  identityTargets: {
    faceShape: string;
    hairstyle: string;
    facialHair: string;
    skinTone: string;
    distinctiveFeatures: string[];
    bodySilhouette: string;
  };
  styleTargets: {
    format: "gingeball-statmuse-inspired-bobblehead";
    finish: "matte-illustrated-3d";
    headScale: number;
    pose: string;
    pedestal: "court-line-data-pedestal";
    lighting: "chalk-ember-rim";
    teamAccent: string;
  };
  outputTargets: {
    posterPath: string;
    modelPath: string;
  };
  status: "ready" | "needs-reference" | "needs-review" | "approved";
}

/** Mathematical design parameters for bobblehead proportion/motion system */
export interface BobbleheadDesignParams {
  headScale: number;        // 1.35-1.65x
  bodyScale: number;        // 0.82-1.0x
  baseRadius: number;       // px
  haloRadius: number;       // 1.15x portrait bounds
  orbitRadius: number;      // 1.25x portrait bounds
  idleAmplitude: number;    // 1-4px float
  idleSpeed: number;        // 4-8 seconds per loop
  ringSweepDuration: number;
  teamAccentStrength: number; // 0.12-0.28 opacity
}

/** Full bobblehead asset entry — links to portrait, poster, model assets */
export interface BobbleheadAssetEntry {
  slug: string;
  name: string;
  team: string;
  nbaPlayerId?: number;
  portraitStaticUrl?: string;
  portraitUrl?: string;
  portraitAnimatedUrl?: string;
  dossierPortraitUrl?: string;
  profileHeroPortraitUrl?: string;
  bobbleheadPosterUrl?: string;
  bobbleheadModelUrl?: string;
  bobbleheadAnimationUrl?: string;
  likenessBrief?: PlayerLikenessBrief;
  portraitStatus: "approved" | "needs-review" | "missing";
  bobbleheadStatus: "approved" | "needs-review" | "missing";
  likenessConfidence: "high" | "medium" | "low";
}

/** Render branch debug output for tracking which asset branch is selected */
export interface BobbleheadRenderDebug {
  slug: string;
  modelUrl?: string;
  posterUrl?: string;
  selectedAssetUrl?: string;
  selectedRenderBranch:
    | "model"
    | "poster"
    | "profile-portrait"
    | "dossier-portrait"
    | "compact-portrait"
    | "fallback";
  fallbackReason?: string;
  loadStatus: "idle" | "loading" | "loaded" | "error";
}

