// ─────────────────────────────────────────────────────────────────────────────
// LOOKUP FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────────

/** Returns full asset entry for a slug, or a missing stub */
export function getPlayerAssets(slug: string): BobbleheadAssetEntry {
  return PLAYER_ASSETS[slug] ?? {
    slug,
    name: slug,
    team: "",
    portraitStatus: "missing",
    bobbleheadStatus: "missing",
    likenessConfidence: "low",
  };
}

/** Determines render branch and returns debug info */
export function getBobbleheadRenderDebug(slug: string): BobbleheadRenderDebug {
  const a = getPlayerAssets(slug);
  const base = { slug, modelUrl: a.bobbleheadModelUrl, posterUrl: a.bobbleheadPosterUrl, loadStatus: "idle" as const };
  if (a.bobbleheadModelUrl && a.bobbleheadStatus === "approved")
    return { ...base, selectedRenderBranch: "model", selectedAssetUrl: a.bobbleheadModelUrl };
  if (a.bobbleheadPosterUrl && a.bobbleheadStatus === "approved")
    return { ...base, selectedRenderBranch: "poster", selectedAssetUrl: a.bobbleheadPosterUrl };
  if (a.profileHeroPortraitUrl && a.portraitStatus === "approved")
    return { ...base, selectedRenderBranch: "profile-portrait", selectedAssetUrl: a.profileHeroPortraitUrl };
  if (a.dossierPortraitUrl && a.portraitStatus === "approved")
    return { ...base, selectedRenderBranch: "dossier-portrait", selectedAssetUrl: a.dossierPortraitUrl };
  if (a.portraitUrl && a.portraitStatus === "approved")
    return { ...base, selectedRenderBranch: "compact-portrait", selectedAssetUrl: a.portraitUrl };
  return { ...base, selectedRenderBranch: "fallback",
    fallbackReason: "Approved bobblehead/model asset missing for this record; using fallback." };
}

/** Coverage report */
export interface AssetCoverageReport {
  total: number; verified: number; needsReview: number; missing: number;
  withPortrait: number; withBobbleheadPoster: number; withBobbleheadModel: number;
  missingPortrait: string[]; missingBobblehead: string[];
}
export function generateCoverageReport(): AssetCoverageReport {
  const all = Object.values(PLAYER_ASSETS);
  const ids = PLAYER_ID_MAP;
  return {
    total: all.length,
    verified: ids.filter(e => e.status === "verified").length,
    needsReview: ids.filter(e => e.status === "needs-review").length,
    missing: ids.filter(e => e.status === "missing").length,
    withPortrait: all.filter(a => !!a.portraitUrl).length,
    withBobbleheadPoster: all.filter(a => !!a.bobbleheadPosterUrl).length,
    withBobbleheadModel: all.filter(a => !!a.bobbleheadModelUrl).length,
    missingPortrait: all.filter(a => a.portraitStatus === "missing").map(a => a.slug),
    missingBobblehead: all.filter(a => a.bobbleheadStatus !== "approved").map(a => a.slug),
  };
}
